SELECT ?attendance
WHERE {
  ?series wdt:P31 wd:Q1363275;
          wdt:P580 ?start;
          wdt:P1923 wd:Q334634;
          wdt:P1923 wd:Q650840.
  FILTER (YEAR(?start) >= 1977 && YEAR(?start) <= 2009).
  ?game wdt:P1545 ?series.
  ?game wdt:P1135 ?attendance.
}
ORDER BY DESC(?attendance)
LIMIT 1

